#!/bin/bash
# Auto-generated Claude Code session demo
# Lesson 23: Session Management

clear
echo -e "\033[90m[Opus] 📁 my-app | 🌿 main\033[0m"
sleep 0.8
echo -e "\033[90m# You closed your terminal at 11 PM\033[0m"
sleep 0.4
echo -e "\033[90m# Next morning:\033[0m"
sleep 0.4
echo -e "\033[33m● Bash\033[0m cd ~/my-project"
sleep 0.8
echo -e "\n\033[1;36m❯\033[0m claude --continue"
sleep 1.2
echo -e "\033[90m# Picks up from last message. Full context restored.\033[0m"
sleep 0.4
echo -e "\033[90m# Or from within an existing session:\033[0m"
sleep 0.4
echo -e "\n\033[1;36m❯\033[0m /continue   # same effect"
sleep 1.2
